svg.script:
// Références aux éléments DOM
const dispMap = document.getElementById('morph_disp');
const morphBlur = document.getElementById('morph_blur');

// Initialisation de l'état de chaque chiffre
let digits = [];
for(let i=0; i<6; i++) {
    digits.push({
        active: 0,
        morphing: false,
        t: 0,
        a: document.getElementById(`t${i}_a`),
        b: document.getElementById(`t${i}_b`),
        group: document.getElementById(`g${i}`)
    });
}

let animating = false;
let lastTime = performance.now();

// Met à jour l'heure et déclenche les morphings
function updateTime() {
    let now = new Date();
    let h = ('0' + now.getHours()).slice(-2);
    let m = ('0' + now.getMinutes()).slice(-2);
    let s = ('0' + now.getSeconds()).slice(-2);
    let timeStr = h + m + s;

    let needAnim = false;

    for(let i=0; i<6; i++) {
        let newChar = timeStr[i];
        let d = digits[i];
        let currentChar = d.active === 0 ? d.a.textContent : d.b.textContent;

        // Si le chiffre change, on prépare le morphing
        if(newChar !== currentChar) {
            let inactiveText = d.active === 0 ? d.b : d.a;
            inactiveText.textContent = newChar;

            d.morphing = true;
            d.t = 0;
            d.group.setAttribute('filter', 'url(#morph_glow)');
            needAnim = true;
        }
    }

    // Démarre la boucle d'animation si nécessaire
    if(needAnim && !animating) {
        animating = true;
        lastTime = performance.now();
        requestAnimationFrame(tick);
    }
}

// Boucle de rendu fluide
function tick() {
    let now = performance.now();
    let dt = now - lastTime;
    lastTime = now;
    if(dt > 100) dt = 100;

    let stillMorphing = false;
    let maxWave = 0;

    for(let i=0; i<6; i++) {
        let d = digits[i];
        if(d.morphing) {
            d.t += dt / 700; // Durée du morphing : 700ms
            if(d.t >= 1) {
                // Fin du morphing
                d.t = 1;
                d.morphing = false;
                d.active = 1 - d.active;
                d.group.removeAttribute('filter');

                d.a.setAttribute('opacity', d.active === 0 ? 1 : 0);
                d.b.setAttribute('opacity', d.active === 1 ? 1 : 0);
                d.a.setAttribute('transform', 'translate(0 0) scale(1)');
                d.b.setAttribute('transform', 'translate(0 0) scale(1)');
            } else {
                // Calcul de l'interpolation
                stillMorphing = true;
                let t = d.t;

                // Fonction d'ease-in-out
                let e = t < 0.5 ? 2*t*t : -1+(4-2*t)*t;
                let wave = Math.sin(t * Math.PI);
                if(wave > maxWave) maxWave = wave;

                let oldText = d.active === 0 ? d.a : d.b;
                let newText = d.active === 0 ? d.b : d.a;

                // Animation des textes : l'ancien descend et rétrécit, le nouveau monte et grandit
                oldText.setAttribute('opacity', 1 - e);
                oldText.setAttribute('transform', `translate(0 ${e * 20}) scale(${1 - e * 0.2})`);

                newText.setAttribute('opacity', e);
                newText.setAttribute('transform', `translate(0 ${-20 + e * 20}) scale(${0.8 + e * 0.2})`);
            }
        }
    }

    // Met à jour l'intensité du filtre de déformation en temps réel
    if(stillMorphing) {
        dispMap.setAttribute('scale', maxWave * 35);
        morphBlur.setAttribute('stdDeviation', maxWave * 6);
        requestAnimationFrame(tick);
    } else {
        animating = false; // Arrête la boucle pour économiser le CPU
    }
}

// Initialisation
updateTime();
setInterval(updateTime, 1000);
